// HTTP Response: { values: [[header1, header2, ...], [row1val1, ...], ...] }
const response = $input.first().json;
const values = response.values || [];

if (values.length < 2) {
  throw new Error('Keine SERP Wettbewerber-Daten im Sheet gefunden');
}

const headers = values[0].map(h => h.toLowerCase().trim());
const urlIdx = headers.indexOf('url');
const titleIdx = headers.indexOf('title');
const posIdx = headers.indexOf('position');
const contentIdx = headers.indexOf('content_text');

const contentTexts = [];
const competitorMeta = [];

for (let i = 1; i < values.length; i++) {
  const row = values[i];
  const contentText = contentIdx >= 0 ? (row[contentIdx] || '') : '';
  if (contentText.trim() !== '') {
    contentTexts.push(contentText);
    competitorMeta.push({
      url: urlIdx >= 0 ? (row[urlIdx] || '') : '',
      title: titleIdx >= 0 ? (row[titleIdx] || '') : '',
      position: posIdx >= 0 ? (row[posIdx] || '') : ''
    });
  }
}

if (contentTexts.length === 0) {
  throw new Error('Keine content_text Daten in SERP Wettbewerber gefunden');
}

return [{
  json: {
    contentTexts,
    competitorMeta,
    competitorCount: contentTexts.length
  }
}];

// HTTP Response: { values: [[header1, header2, ...], [row1val1, ...], ...] }
const response = $input.first().json;
const values = response.values || [];

if (values.length < 2) {
  throw new Error('Keine Keywords im Sheet gefunden');
}

const headers = values[0].map(h => h.toLowerCase().trim());
const kwIdx = headers.indexOf('keyword');

if (kwIdx === -1) {
  throw new Error('Spalte keyword nicht im Keywords-Sheet gefunden. Headers: ' + headers.join(', '));
}

const keywords = [];
for (let i = 1; i < values.length; i++) {
  const kw = (values[i][kwIdx] || '').trim();
  if (kw !== '' && kw !== 'Keine Ergebnisse') {
    keywords.push(kw);
  }
}

if (keywords.length === 0) {
  throw new Error('Keine gueltigen Keywords gefunden');
}

return [{
  json: {
    keywords,
    keywordCount: keywords.length
  }
}];

// Cosine Similarity berechnen
const allItems = $input.all();

if (allItems.length < 2) {
  throw new Error('Merge lieferte nur ' + allItems.length + ' Items. Erwartet: 2 (Content + Keywords). Pruefen ob beide Branches liefen.');
}

// Content Embeddings (erstes Item von Voyage AI Content)
const contentResponse = allItems[0].json;
const contentEmbeddings = contentResponse.data ? contentResponse.data.map(d => d.embedding) : [];

// Keyword Embeddings (zweites Item von Voyage AI Keywords)
const keywordResponse = allItems[1].json;
const keywordEmbeddings = keywordResponse.data ? keywordResponse.data.map(d => d.embedding) : [];

// Metadaten laden
const competitorMeta = $('Prepare Embedding Inputs').first().json.competitorMeta;
const keywords = $('Prepare Keyword Queries').first().json.keywords;

// Similarity Matrix berechnen: Keywords (Zeilen) x Wettbewerber (Spalten)
const matrix = [];
const totalCompetitors = contentEmbeddings.length;

for (let ki = 0; ki < keywordEmbeddings.length; ki++) {
  const row = {
    keyword: keywords[ki],
    scores: {},
    avgScore: 0,
    maxScore: 0,
    minScore: 1,
    coverageCount: 0
  };
  let totalScore = 0;

  for (let ci = 0; ci < contentEmbeddings.length; ci++) {
    const vecA = keywordEmbeddings[ki];
    const vecB = contentEmbeddings[ci];
    let dotProduct = 0;
    let normA = 0;
    let normB = 0;
    for (let i = 0; i < vecA.length; i++) {
      dotProduct += vecA[i] * vecB[i];
      normA += vecA[i] * vecA[i];
      normB += vecB[i] * vecB[i];
    }
    normA = Math.sqrt(normA);
    normB = Math.sqrt(normB);
    const score = (normA === 0 || normB === 0) ? 0 : dotProduct / (normA * normB);
    const roundedScore = Math.round(score * 1000) / 1000;

    const competitorLabel = competitorMeta[ci] ? (competitorMeta[ci].title || competitorMeta[ci].url || 'Competitor_' + (ci+1)) : 'Competitor_' + (ci+1);
    row.scores[competitorLabel] = roundedScore;
    totalScore += roundedScore;
    if (roundedScore > row.maxScore) row.maxScore = roundedScore;
    if (roundedScore < row.minScore) row.minScore = roundedScore;
    if (roundedScore > 0.7) row.coverageCount++;
  }

  row.avgScore = contentEmbeddings.length > 0 ? Math.round((totalScore / contentEmbeddings.length) * 1000) / 1000 : 0;
  matrix.push(row);
}

const commodityTopics = matrix.filter(r => r.coverageCount === totalCompetitors && r.avgScore > 0.7);
const differentiationTopics = matrix.filter(r => r.coverageCount > 0 && r.coverageCount < totalCompetitors);
const gapTopics = matrix.filter(r => r.coverageCount === 0);

return [{
  json: {
    matrix: matrix,
    summary: {
      totalKeywords: keywords.length,
      totalCompetitors: totalCompetitors,
      commodityCount: commodityTopics.length,
      differentiationCount: differentiationTopics.length,
      gapCount: gapTopics.length
    },
    commodityTopics: commodityTopics.map(r => ({ keyword: r.keyword, avgScore: r.avgScore })),
    differentiationTopics: differentiationTopics.map(r => ({ keyword: r.keyword, avgScore: r.avgScore, coverage: r.coverageCount + '/' + totalCompetitors })),
    gapTopics: gapTopics.map(r => ({ keyword: r.keyword, avgScore: r.avgScore })),
    competitorMeta: competitorMeta,
    keywords: keywords
  }
}];

