// Claude API Response parsen
const claudeResponse = $input.first().json;

let responseText = '';
if (claudeResponse.content && Array.isArray(claudeResponse.content)) {
  responseText = claudeResponse.content.filter(c => c.type === 'text').map(c => c.text).join('');
} else if (typeof claudeResponse.content === 'string') {
  responseText = claudeResponse.content;
} else if (claudeResponse.message && claudeResponse.message.content) {
  const content = claudeResponse.message.content;
  if (Array.isArray(content)) {
    responseText = content.filter(c => c.type === 'text').map(c => c.text).join('');
  } else {
    responseText = String(content);
  }
} else {
  responseText = claudeResponse.text || claudeResponse.output || JSON.stringify(claudeResponse);
}

let analysisData;
try {
  analysisData = JSON.parse(responseText);
} catch (e) {
  const jsonMatch = responseText.match(/```(?:json)?\s*([\s\S]*?)```/);
  if (jsonMatch) {
    analysisData = JSON.parse(jsonMatch[1].trim());
  } else {
    const jsonBlockMatch = responseText.match(/\{[\s\S]*\}/);
    if (jsonBlockMatch) {
      analysisData = JSON.parse(jsonBlockMatch[0]);
    } else {
      throw new Error('Konnte kein JSON in der Claude-Antwort finden: ' + responseText.substring(0, 200));
    }
  }
}

const rows = [];

if (analysisData.commodity_topics) {
  for (const topic of analysisData.commodity_topics) {
    rows.push({ analyse_typ: 'commodity', keyword_oder_thema: topic.keyword_oder_thema || topic.keyword || '', score: topic.score || 0, details: topic.details || '', kategorie: 'Commodity Topic' });
  }
}

if (analysisData.differenzierung_themen) {
  for (const topic of analysisData.differenzierung_themen) {
    rows.push({ analyse_typ: 'differenzierung', keyword_oder_thema: topic.keyword_oder_thema || topic.keyword || '', score: topic.score || 0, details: (topic.details || '') + (topic.abgedeckt_von ? ' | Abgedeckt von: ' + topic.abgedeckt_von.join(', ') : ''), kategorie: 'Differenzierung' });
  }
}

if (analysisData.luecken) {
  for (const topic of analysisData.luecken) {
    rows.push({ analyse_typ: 'luecke', keyword_oder_thema: topic.keyword_oder_thema || topic.keyword || '', score: topic.score || 0, details: topic.details || '', kategorie: 'Content-Luecke' });
  }
}

if (analysisData.zusammenfassung) {
  rows.push({ analyse_typ: 'zusammenfassung', keyword_oder_thema: 'Gesamtanalyse', score: 0, details: analysisData.zusammenfassung, kategorie: 'Zusammenfassung' });
}

if (rows.length === 0) {
  rows.push({ analyse_typ: 'info', keyword_oder_thema: 'Keine Ergebnisse', score: 0, details: 'Claude hat keine strukturierten Ergebnisse geliefert', kategorie: 'Info' });
}

return rows.map(row => ({ json: row }));

// Alle Items sammeln und als 2D-Array fuer Google Sheets formatieren
const items = $input.all();
const spreadsheetId = $('Execute Workflow Trigger').first().json.spreadsheet_id;

const headers = ['analyse_typ', 'keyword_oder_thema', 'score', 'details', 'kategorie'];
const rows = [headers];

for (const item of items) {
  rows.push([
