    item.json.keyword_oder_thema || '',
    String(item.json.score || 0),
    item.json.details || '',
    item.json.kategorie || ''
  ]);
}

return [{
  json: {
    spreadsheet_id: spreadsheetId,
    values: rows
  }
}];

